cd /d "C:\Users\Administrator\Desktop\plc2" && powershell -Command "
[Reflection.Assembly]::LoadWithPartialName('System.Windows.Forms') | Out-Null
Add-Type -AssemblyName PresentationCore

try {
  \$pdfPath = 'top 디자이너 메뉴얼 안봐도됨.pdf'
  if (Test-Path \$pdfPath) {
    \$file = Get-Item \$pdfPath
    Write-Host \"파일 크기: \$([Math]::Round(\$file.Length / 1MB, 2)) MB\"
    Write-Host \"파일 있음: \$\$TRUE\"
  }
} catch {
  Write-Host \"오류: \$_\"
}
"

powershell -Command "
\$pdfPath = 'C:\Users\Administrator\Desktop\plc2\top 디자이너 메뉴얼 안봐도됨.pdf'
